'use client';
import * as React from 'react';
import { Card, CardContent, CardHeader } from '@/components/ui/card';
import { AlertTriangle, RefreshCcw } from 'lucide-react';
import { DashboardList, DashboardListItem } from '@/components/ui/dashboard-list';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
type Ingredient = any;

interface LowStockAlertsProps {
  ingredients: Ingredient[];
}

export function LowStockAlerts({ ingredients }: LowStockAlertsProps) {
  const lowStockIngredients = React.useMemo(() => {
    return ingredients
      .filter(ing => {
        const stock = ing.stock_actual ?? ing.stock ?? 0;
        const min = ing.stock_minimo_alerta ?? ing.alert_min ?? ing.stock_minimo ?? 0;
        return stock <= min && min > 0;
      })
      .sort((a, b) => {
        const stockA = a.stock_actual ?? a.stock ?? 0;
        const minA = a.stock_minimo_alerta ?? a.alert_min ?? a.stock_minimo ?? 1;
        const stockB = b.stock_actual ?? b.stock ?? 0;
        const minB = b.stock_minimo_alerta ?? b.alert_min ?? b.stock_minimo ?? 1;
        return (stockA / minA) - (stockB / minB);
      })
      .slice(0, 5);
  }, [ingredients]);

  return (
    <Card className="h-full w-full">
      <CardHeader 
        title="Alertas de Stock Bajo" 
        icon={AlertTriangle} 
      />
      <CardContent className="pt-0">
        <DashboardList className="divide-y-0 space-y-2">
          {lowStockIngredients.length > 0 ? (
            lowStockIngredients.map(ing => {
              const stock = ing.stock_actual ?? ing.stock ?? 0;
              const min = ing.stock_minimo_alerta ?? ing.alert_min ?? ing.stock_minimo ?? 0;
              const isCritical = stock < (min * 0.2);
              return (
                <DashboardListItem
                  key={ing.id || ing._id}
                  className={cn(
                    "px-3 rounded-lg border transition-colors h-[56px] py-0",
                    isCritical 
                      ? "bg-destructive/5 border-destructive/20" 
                      : "bg-amber-500/5 border-amber-500/20"
                  )}
                  title={ing.nombre_ingrediente || ing.name}
                  subtitle={`${stock} / ${min} ${ing.unidad_medida || ing.unit || 'uds'}`}
                  suffix={
                    <Button variant="ghost" size="md">
                      <RefreshCcw />
                    </Button>
                  }
                />
              );
            })
          ) : (
            <div className="py-10 text-center text-sm text-muted-foreground">
              Todo en orden
            </div>
          )}
        </DashboardList>
      </CardContent>
    </Card>
  );
}
